def create_secure_server(
    port: int = 50051,
    server_cert_path: str = "server.crt",
    server_key_path: str = "server.key",
    ca_cert_path: str = "ca.crt",
    max_workers: int = 10,
) -> grpc.Server:
    """Create a TLS-secured gRPC server (recommended for production)."""

    token_store.add_token("user-token-abc123", "alice", is_admin=False)
    token_store.add_token("admin-token-xyz789", "admin-carol", is_admin=True)

    interceptors = [
        AuditLoggingInterceptor(),
        AuthenticationInterceptor(token_store),
    ]

    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=max_workers),
        interceptors=interceptors,
    )

    # Load TLS credentials
    try:
        with open(server_key_path, "rb") as f:
            server_key = f.read()
        with open(server_cert_path, "rb") as f:
            server_cert = f.read()
        with open(ca_cert_path, "rb") as f:
            ca_cert = f.read()

        credentials = grpc.ssl_server_credentials(
            [(server_key, server_cert)],
            root_certificates=ca_cert,
            require_client_auth=False,  # Set True for mTLS
        )
        server.add_secure_port(f"[::]:{port}", credentials)
        logger.info(f"Secure server configured on port {port} with TLS")
    except FileNotFoundError as e:
        logger.error(f"TLS certificate file not found: {e}")
        raise

    return server


